t.script:
document.addEventListener('DOMContentLoaded', function () {
    // 1. Initial Counters from Server
    let bankCounter = ;
    let familyCounter = ;
    let educationCounter = ;

    const prefix = 'ahadu_onboarding_';
    const form = document.getElementById('ahadu_onboarding_form');

    // --- Dynamic Add Functions ---
    window.addBankRow = function(isUserAction = true) {
        const template = document.getElementById('bank_row_template').innerHTML;
        const container = document.getElementById('bank_lines_container');
        const newRow = document.createElement('div');
        newRow.innerHTML = template.replace(/name="([a-z_]+)_"/g, 'name="$1_' + bankCounter + '"');
        container.appendChild(newRow.firstElementChild);
        bankCounter++;
        if(isUserAction) {
            localStorage.setItem(prefix + 'added_bank_count', (parseInt(localStorage.getItem(prefix + 'added_bank_count') || 0) + 1));
            bindInputListeners(newRow); // Bind listeners to new inputs
        }
    }

    window.addFamilyRow = function(isUserAction = true) {
        const template = document.getElementById('family_row_template').innerHTML;
        const container = document.getElementById('family_lines_container');
        const newRow = document.createElement('div');
        newRow.innerHTML = template.replace(/name="([a-z_]+)_"/g, 'name="$1_' + familyCounter + '"');
        container.appendChild(newRow.firstElementChild);
        familyCounter++;
        if(isUserAction) {
            localStorage.setItem(prefix + 'added_family_count', (parseInt(localStorage.getItem(prefix + 'added_family_count') || 0) + 1));
            bindInputListeners(newRow);
        }
    }

    window.addEducationRow = function(isUserAction = true) {
        const template = document.getElementById('education_row_template').innerHTML;
        const container = document.getElementById('education_lines_container');
        const newRow = document.createElement('div');
        newRow.innerHTML = template.replace(/name="([a-z_]+)_"/g, 'name="$1_' + educationCounter + '"');
        container.appendChild(newRow.firstElementChild);
        educationCounter++;
        if(isUserAction) {
            localStorage.setItem(prefix + 'added_edu_count', (parseInt(localStorage.getItem(prefix + 'added_edu_count') || 0) + 1));
            bindInputListeners(newRow);
        }
    }

    if (form) {
        // --- 2. Restore Dynamic Rows ---
        const savedBankCount = parseInt(localStorage.getItem(prefix + 'added_bank_count') || 0);
        for(let i=0; i < savedBankCount; i++) addBankRow(false);

        const savedFamilyCount = parseInt(localStorage.getItem(prefix + 'added_family_count') || 0);
        for(let i=0; i < savedFamilyCount; i++) addFamilyRow(false);

        const savedEduCount = parseInt(localStorage.getItem(prefix + 'added_edu_count') || 0);
        for(let i=0; i < savedEduCount; i++) addEducationRow(false);

        // --- 3. Restore Input Values ---
        const allInputs = form.querySelectorAll('input:not([type="hidden"]):not([type="file"]), select, textarea');
        let restoredCount = 0;
        allInputs.forEach(input => {
            const savedVal = localStorage.getItem(prefix + input.name);
            if (savedVal !== null) {
                input.value = savedVal;
                restoredCount++;
            }
        });

        // Show alert if data was restored
        if (restoredCount > 0) {
            document.getElementById('draft_alert').classList.remove('d-none');
        }

        // --- 4. Bind Save Listeners ---
        function bindInputListeners(scope) {
            const inputs = scope.querySelectorAll('input:not([type="hidden"]):not([type="file"]), select, textarea');
            inputs.forEach(input => {
                input.addEventListener('input', function() {
                    localStorage.setItem(prefix + this.name, this.value);
                });
                input.addEventListener('change', function() {
                    localStorage.setItem(prefix + this.name, this.value);
                });
            });
        }

        // Initial bind for all inputs currently on page
        bindInputListeners(form);

        // --- 5. Save/Restore Active Tab ---
        const tabLinks = document.querySelectorAll('button[data-bs-toggle="tab"]');
        tabLinks.forEach(tab => {
            tab.addEventListener('shown.bs.tab', function (e) {
                localStorage.setItem(prefix + 'active_tab', e.target.id);
            });
        });
        const activeTabId = localStorage.getItem(prefix + 'active_tab');
        if (activeTabId) {
            const tabTriggerEl = document.getElementById(activeTabId);
            if (tabTriggerEl) {
                // Fallback native click if bootstrap tab object isn't globally active
                tabTriggerEl.click();
            }
        }

        // --- 6. Form Validation and Missing Fields Toast ---
        const submitBtn = document.getElementById('btn_submit_onboarding');
        if (submitBtn) {
            submitBtn.addEventListener('click', function(e) {
                if (!form.checkValidity()) {
                    e.preventDefault(); // Stop form submission

                    const invalidInputs = form.querySelectorAll(':invalid');
                    if (invalidInputs.length > 0) {
                        const firstInvalid = invalidInputs[0];

                        // 6.1 Open the tab containing the first invalid input
                        const tabPane = firstInvalid.closest('.tab-pane');
                        if (tabPane) {
                            const tabId = tabPane.id;
                            const tabTrigger = document.querySelector('button[data-bs-target="#' + tabId + '"]');
                            if (tabTrigger) {
                                // Natively click the tab to show it
                                tabTrigger.click();
                            }
                        }

                        // 6.2 Gather missing field labels safely
                        let missingNames =[];
                        const maxToasts = 6; // Limit items to avoid huge popups

                        invalidInputs.forEach((input, index) => {
                            let labelText = '';

                            // Method 1: Check by input "id" and "for" attribute
                            if (input.id) {
                                const label = form.querySelector('label[for="' + input.id + '"]');
                                if (label) labelText = label.textContent.replace('*', '').trim();
                            }

                            // Method 2: Check closest container containing a label (works well for dynamic rows)
                            if (!labelText) {
                                const parentWrapper = input.closest('.mb-3') || input.closest('div');
                                if (parentWrapper) {
                                    const label = parentWrapper.querySelector('label');
                                    if (label) labelText = label.textContent.replace('*', '').trim();
                                }
                            }

                            // Method 3: Fallback to the name attribute
                            if (!labelText) {
                                labelText = input.name || 'Unknown Field';
                            }

                            // Add to list if it's unique and within our display limit
                            if (index < maxToasts && !missingNames.includes(labelText)) {
                                missingNames.push('<li>' + labelText + '</li>');
                            }
                        });

                        // 6.3 Build and Show the Toast manually (safest cross-version Odoo method)
                        let toastHtml = '<strong>Please fix the following required/invalid fields:</strong><ul class="mt-2 mb-0 ps-3">' + missingNames.join('') + '</ul>';

                        if (invalidInputs.length > maxToasts) {
                            toastHtml += '<div class="mt-2"><small>...and ' + (invalidInputs.length - maxToasts) + ' more field(s).</small></div>';
                        }

                        const toastBody = document.getElementById('validationToastBody');
                        if (toastBody) {
                            toastBody.innerHTML = toastHtml;
                            const toastEl = document.getElementById('validationToast');

                            // Force display block to avoid Bootstrap JS dependency
                            toastEl.style.display = 'block';
                            toastEl.classList.add('show');
                            toastEl.style.opacity = '1';

                            // Auto hide after 8 seconds
                            setTimeout(() => {
                                toastEl.classList.remove('show');
                                toastEl.style.opacity = '0';
                                setTimeout(() => {
                                    toastEl.style.display = 'none';
                                }, 300);
                            }, 8000);
                        }

                        // 6.4 Focus the first invalid input so the user sees it
                        setTimeout(() => {
                            firstInvalid.focus();
                        }, 200);
                    }
                }
            });
        }

        // --- 7. Clear Storage on Submit ---
        form.addEventListener('submit', function() {
            Object.keys(localStorage).forEach(key => {
                if (key.startsWith(prefix)) {
                    localStorage.removeItem(key);
                }
            });
        });
    }
});
